var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이잇…! 이딴 조무래기들에게까지 고전해야 한다고?","JPN":"きいっ……！　こんな雑魚にまで苦戦するなんて。","ENG":"Ngh...! I'm struggling to deal with these chumps?","TWN":"蛤……！遇到這種小嘍囉，還要進行激戰？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"어디서 함부로 덤벼! 원래는 한 주먹거리도 안 되는 것들이!!","JPN":"来るなっ！　いつもなら一発で余裕で叩きのめせるのに！！","ENG":"It dares to come at me?! If I had my strength, I could knock it out in one punch!","TWN":"儘管放馬過來吧！看我一拳打爆你們！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_22"},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아얏! 깨물지 마! 아야! 찌르지 마! 아야! 아야야!","JPN":"痛っ！　噛まないでよ！　痛い！　刺すなって！　イタッ！　イタタ！","ENG":"Oww!! Stop biting me! Ouch! No stabbing! Oww!! OWWW!!!","TWN":"哎呀！別咬！哎呀！別刺！哎呀！哎呀呀！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_21"},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록, 콜록…!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러게 제 옆에서 떨어지지 말라고 했잖아요. 움직일 수 있겠어요?","JPN":"ですから私のそばを離れるなと言ったではないですか。動けますか？","ENG":"I thought I told you to stay close. Can you move?","TWN":"我不是說了別離開我身邊嘛。你還能動嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으으으……. 온몸이 너덜너덜해.","JPN":"ううう……全身ボロボロ。","ENG":"Oof... my body's aching all over.","TWN":"嗚嗚……整個身體都是傷。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰나는 거짓말쟁이! 침실만 지키면 되는 심부름이라더니 고생만 잔뜩이야!","JPN":"シェナの嘘つき！　寝室を守るだけの簡単な仕事だって聞いたのに、苦労ばっかり！","ENG":"Shena, you liar! You said this would be an easy job! Well, it's not!!","TWN":"世娜那個騙子！說什麼只要守住臥室就行，結果卻讓我吃了這麼多苦！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"어쩌죠? 다시 몰려오려나 봐요. 수가 너무 많아요.","JPN":"どうしましょう？　また押し寄せてきそうです。数が多すぎます。","ENG":"Oh no! I think they're coming back. There are too many of them!","TWN":"怎麼辦？它們好像又聚集過來了。而且數量很多。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"끝이 안 나는군. 이대로는 맥크레디 양 몸이 못 버티겠어.","JPN":"きりがないな。このままではマクレディー君の身が持たん。","ENG":"There seems to be no end. At this rate, Regina won't withstand any longer.","TWN":"沒完沒了啊。照這樣下去，麥克蕾蒂的身體該撐不住了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……그래요. 저 혼자서는 더 감당하긴 어렵겠어요.","JPN":"……そうですね。私一人でこれ以上耐えるのは難しそうです。","ENG":"...You are right. I cannot handle them all on my own.","TWN":"……是啊，我一個人很難繼續撐下去。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나, 제 뒤에 업히세요. 일단은 저 침식체들을 따돌려야겠어요.","JPN":"ルナさん、私の背におぶさってください。とりあえずあの侵食体たちをまきます。","ENG":"Luna, hop on my back. We must lose those C.O.s for now.","TWN":"露娜，到我背上來。得先甩掉那些侵蝕體才行。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐 해요, 어서 업히라니까!","JPN":"何してるのですか？　早くおぶさって！","ENG":"What are you waiting for?! Hurry!","TWN":"愣著幹嘛，快上來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 알았어!","JPN":"わ、わかったよ！","ENG":"Oh, okay!","TWN":"知…知道了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"뒤, 뒤에 바짝 따라붙었어요!","JPN":"う、後ろにぴったり付いてきています！","ENG":"Th-they're right behind us!!","TWN":"緊…緊跟在後面呢！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"잡히면 저희는 어떻게 되는 거죠? 설마 루나 님처럼 갈기갈기 찢어질까요?","JPN":"捕まったらどうなるのでしょう？　まさか、ルナ様のようにずたずたにされるのでしょうか？","ENG":"What'll happen if they catch us? Will we be ripped to shreds like Ms. Luna?!","TWN":"被抓住的話我們會怎麼樣？不會像露娜一樣被撕成碎片吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"돌아보지 말고 앞만 봐요! 뒤는 없다고 생각하고!","JPN":"振り返らずに前だけを見て！　後ろはないと思いなさい！","ENG":"Do not look behind! Just RUN!!","TWN":"別回頭，一直往前看！我們沒有回頭路可走！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아……! 하아……!","JPN":"はあ……！　はあ……！","ENG":"*Huff…!* *Huff…!*","TWN":"呼呼……！呼呼……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부학회장, 너도 몸 상태가 안 좋은 거 아냐? 정말 이래도 돼?","JPN":"副学会長、あんたも具合が悪いんじゃないの？　本当にこれでいいの？","ENG":"Hey, Vice President, aren't you still in recovery too? You sure you want to do this?","TWN":"副學會長，你的身體狀況也不太好吧？這樣下去真的沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말 시키지 마요! 숨 차니까!","JPN":"話しかけないで！　息切れしますから！","ENG":"Stop talking to me! I am out of breath as it is!","TWN":"別跟我說話！我快要喘不過氣來了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그림자 주제에 왜 그렇게 사람처럼 굴어요? 죽으려면 그냥 조용히 죽을 것이지!","JPN":"シャドウのくせになぜ人間のように振る舞うのですか？　死にたいのならおとなしく死になさい！","ENG":"You are a Shadow, so act like one! And if you are going to die, do it quietly!","TWN":"你作為一個暗影，也太像人了吧？要死就安靜地死遠點！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음……?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조심하게, 맥크레디 양! 앞에도 침식체들이 있어!","JPN":"気をつけたまえ、マクレディー君！　前にも侵食体がいるぞ！","ENG":"Regina, look out! There are C.O.s in front of you!","TWN":"小心，麥克蕾蒂！前面也有侵蝕體！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"꺄악!?","JPN":"きゃあっ！？","ENG":"Kyaaah!!","TWN":"哎呀！？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_BIG"},{"id":"L40_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아윽!!","JPN":"あうっ！！","ENG":"Errgh!","TWN":"唔呃！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님…!","JPN":"副学会長様……！","ENG":"Ms. Vice President...!","TWN":"副學會長……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"어, 어쩌면 좋아. 피가 나요, 부학회장님.","JPN":"ど、どうしよう。血が出ています、副学会長様。","ENG":"O-oh no... Y-you're bleeding...","TWN":"怎…怎麼辦，你流血了，副學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그 부학회장에게 깔려 있는 나도 신경 좀 써 줘….","JPN":"その副学会長の下敷きになってるアタシのこともちょっとは気遣ってよ……","ENG":"Hey, um... Could you also worry about me too? I'm being crushed by her...","TWN":"拜託你也關心一下被副學會長壓在下面的我……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큭……! 누가 이 정도에 맥없이 쓰러져 줄 것 같아요?","JPN":"くっ……！　この程度であっけなくやられたりしません！","ENG":"Kgh...! Do you really think that is enough to stop me?","TWN":"咳……！你們以為我會這麼軟弱地倒下嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"장거리에서 공격할 수 있는 부류들이군. 이대로는 다음 공격으로 우리 모두 벌집이 될 걸세.","JPN":"長距離から攻撃できる部類だな。このままでは次の攻撃で我々全員ハチの巣になってしまう。","ENG":"It looks like they can attack from long distances. If we don't come up with a plan, their next attack will turn us into Swiss cheese.","TWN":"是可以遠距離攻擊的類型。照這樣下去，下次攻擊時我們都會被打成蜂窩。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그럴 수가……","JPN":"そんな……","ENG":"Oh no...","TWN":"怎麼會……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그, 그럼 제가 미끼가 될게요! 시선을 끌 테니까 그동안 안전한 곳으로 도망치세요!","JPN":"で、では私が囮になります！　注意を引きつけておきますから、その隙に安全な場所に逃げてください！","ENG":"Th-then I'll be the bait! I'll draw their attention while everyone else runs to safety!","TWN":"那…那我來當誘餌！我會吸引它們的注意力，你趁機逃到安全的地方！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"미끼라니요? 웃기지 마세요!","JPN":"囮ですって？　ふざけないでください！","ENG":"Bait? No, you will not!","TWN":"說什麼誘餌？別搞笑了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님을 위해선 이 방법뿐이에요.","JPN":"副学会長様のためにはこの手しかありません。","ENG":"But it's the only way to save you, ma'am...","TWN":"為了副學會長，就只有這個辦法了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"여기서 제일 필요 없는 건 저인 걸요. 침식체들이 속아 줄지는 모르겠지만……","JPN":"この中で一番必要ないのは私ですから。侵食体が騙されてくれるかわかりませんけど……","ENG":"I'm the most useless one here. But I'm not sure if the C.O.s will be fooled...","TWN":"這裡最沒用的人就是我。不知道侵蝕體會不會上當……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 앞에서 그딴 말도 안 되는 소리는──","JPN":"私の前でそのようなばかなことは――","ENG":"Stop talking nonsense in front–","TWN":"在我面前，別說這種莫名其妙的話——"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"──집어 치우라고요.","JPN":"――言わないでください。","ENG":"–of me.","TWN":"—— 聽我的指揮就好。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부학회장, 저기 봐. 조무래기들이 물러나고 있어.","JPN":"副学会長、あれ見て。雑魚どもが引いていくよ。","ENG":"Hey, look! They're retreating.","TWN":"副學會長，看那邊。小嘍囉們撤退了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_01"},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 저 종소리는 파수꾼들에게 물러나라는 신호 같군.","JPN":"どうやらあの鐘の音は番人に引けという合図だったようだ。","ENG":"I guess that bell signaled them to stand down.","TWN":"看來那個鐘聲，好像就是向守衛發出的撤退訊號。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"수도원이 우리를 손님으로 인정해 준 모양일세.","JPN":"修道院が我々を客として認めてくれたようだな。","ENG":"I believe the monastery has accepted us as their guests.","TWN":"修道院好像承認我們是客人了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으하아아……. 할 거면 좀 빨리 하지. 망할 인간들 같으니.","JPN":"ぷはああ……やるならもっと早くやってくれよ。クソ人間どもめ。","ENG":"Ugh... Well, they should've done it sooner. Stupid humans...","TWN":"啊啊啊……既然要承認為什麼不快點，這些可惡的人類。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"다행이다……. 실은 결심하고 나서도 발이 안 떨어졌거든요……","JPN":"よかった……実は決心してからも足が動かなくて……","ENG":"Phew... To be honest, I couldn't move my feet even after I made up my mind...","TWN":"太好了……其實我下定決心後也沒邁開腳……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"졸지에 생각지도 못하게 죽을 고비를 넘겼네요.","JPN":"突然思いもかけず窮地を脱しましたわね。","ENG":"We managed to avoid death in the most unimaginable way possible.","TWN":"沒想到闖過了生死關頭。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실키, 다음부터 절대 그런 무모한 짓은 하지 마세요.","JPN":"シルキー、次からは絶対にそのような無茶なことはしないでください。","ENG":"Sylkie, please do not try or say anything like that again.","TWN":"思琪，下次千萬不要再做那麼魯莽的事了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네? 그렇지만 전……","JPN":"はい？　でも私は……","ENG":"Huh...? B-but I─","TWN":"啊？可是我……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"해명은 없습니다. 그저 누가 죽는 꼴을 보기 싫어서예요.","JPN":"言い訳は聞きません。ただ誰かが死ぬ姿を見たくないだけです。","ENG":"No excuses. I just do not want to see anyone get killed.","TWN":"別解釋。我只是不想看到有人死掉。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"죄송해요, 부학회장님. 제가 잘못 생각했어요.","JPN":"申し訳ございません、副学会長様。私が間違っていました。","ENG":"I'm sorry, ma'am. I was wrong.","TWN":"對不起，副學會長，是我想得不夠周到。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요. 앞으로는 두 번 다시 그러면 안 돼요.","JPN":"いいでしょう。これからは二度としないでください。","ENG":"Very well. Promise me you will not do that again.","TWN":"好，以後不許再那樣了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 상대가 생각을 바꾸기 전에 종소리가 들린 쪽으로 가 보세나.","JPN":"マクレディー君、相手の考えが変わらないうちに鐘の音がした方に進もうではないか。","ENG":"Regina, let's head to where we heard the bells ring before our hosts change their minds.","TWN":"麥克蕾蒂，在對方改變想法之前，先去鐘聲傳來的那邊看看吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 어서 가죠.","JPN":"そうですわね。行きましょう。","ENG":"Agreed. Let's go.","TWN":"是啊，快走吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"누가 이딴 것들을 풀어 놨는지 제 두 눈으로 꼭 확인해야겠어요.","JPN":"誰がこんなものを解き放ったのか、私の目でしかと確かめますわ。","ENG":"I would like to see for myself who let those things loose in the wild.","TWN":"我要親眼看看是誰放出來的這種東西。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};